import './css/MyWork.css'
import beelweb from './img/beelweb.jpg'
import mypackage from './img/Cloves.png'
import sirivc from './img/sirivc.jpg'
import siri from './img/siri.jpg'
import beel from './img/Beel.png'

function MyWork() {
    return (
        <>



            <div className="work-wrap" style={{ backgroundColor: "rgb(238 238 238)" }}>
                <div className="work-info">
                    <i class="fab fa-product-hunt badge"></i>
                    <p className="work-info-name">Package Design</p>
                    <p className="work-info-title">Package Design for a Organic food startup</p>
                </div>
                <img src={mypackage} alt="work"></img>
            </div>


            <div className="work-wrap" style={{ backgroundColor: "rgb(43 46 53)" }}>
                <div className="work-info">
                    <i class="fas fa-crown  badge"></i>
                    <p className="work-info-name" style={{ color: "white" }}>Brand Design</p>
                    <p className="work-info-title" style={{ color: "white" }}>Brand Design for a Jewellery Rentals tartup</p>
                </div>
                <img src={siri} alt="work"></img>
            </div>


            <div className="work-wrap" style={{ backgroundColor: "rgb(243 209 208)" }}>
                <div className="work-info">
                    <i class="far fa-address-card badge"></i>
                    <p className="work-info-name">VC Design</p>
                    <p className="work-info-title">VC Design for a Jewellery Rentals startup</p>
                </div>
                <img src={sirivc} alt="work"></img>
            </div>

            <div className="work-wrap" style={{ backgroundColor: "#009aff" }}>
                <div className="work-info">
                    <i class="fas fa-crown  badge"></i>
                    <p className="work-info-name">Branding</p>
                    <p className="work-info-title">Avatar Design for Beel Discord Bot</p>
                </div>
                <img src={beel} alt="work"></img>
            </div>


            <div className="work-wrap" style={{ backgroundColor: "rgb(81 186 254)" }}>
                <div className="work-info">
                    <i class="fas fa-globe badge"></i>
                    <p className="work-info-name">Web Design</p>
                    <p className="work-info-title">WebSite designed for Beel Bot</p>
                </div>
                <img src={beelweb} alt="work"></img>
            </div>
        </>
    );
}

export default MyWork;